INSERT INTO translations (language_code, namespace, content)
VALUES 
('ar', 'advisory', '{"advisory":{"hero":{"title":"خدمات","title_highlight":"استشارية استراتيجية","description":"إرشادات الخبراء والمشورة الاستراتيجية للتعامل مع تحديات الأعمال المعقدة وتسريع النمو.","cta_button":"جدولة استشارة"},"key_features":{"title":"حلول استشارية شاملة","features":[{"title":"التخطيط الاستراتيجي","description":"تطوير استراتيجيات أعمال شاملة متوافقة مع فرص السوق وأهداف الشركة.","icon":"Target"},{"title":"تحليل السوق","description":"بحث سوقي معمق وذكاء تنافسي لاتخاذ قرارات استراتيجية.","icon":"BarChart3"},{"title":"استراتيجية النمو","description":"تحديد وتنفيذ فرص النمو بما في ذلك الاندماج والاستحواذ والشراكات وتوسيع السوق.","icon":"TrendingUp"},{"title":"أسواق رأس المال","description":"إرشادات خبراء حول جمع رأس المال واستهداف المستثمرين واستراتيجيات تحديد المواقع في السوق.","icon":"DollarSign"},{"title":"حوكمة الشركات","description":"أفضل الممارسات لفعالية مجلس الإدارة وعلاقات المساهمين والامتثال للمعايير البيئية والاجتماعية.","icon":"Shield"},{"title":"تدريب التنفيذيين","description":"تطوير القيادة وتدريب التواصل التنفيذي لكبار المسؤولين التنفيذيين.","icon":"Users"}]},"benefits":{"title":"لماذا تختار استشارات AmplifiX","items":[{"title":"خبرة القطاع","description":"معرفة عميقة بالقطاعات عبر التكنولوجيا والرعاية الصحية والمالية والصناعات الناشئة."},{"title":"سجل حافل","description":"نتائج ناجحة للشركات من مرحلة ما قبل الاكتتاب العام إلى Fortune 500."},{"title":"نهج متكامل","description":"خدمات استشارية متكاملة بسلاسة مع منصات IR/PR والتحليلات لدينا."},{"title":"موثوق وسري","description":"بروتوكولات سرية صارمة وعلاقات مستشار موثوق مبنية على النزاهة."}]}}}'),
('ro', 'advisory', '{"advisory":{"hero":{"title":"Servicii","title_highlight":"Consultanță Strategică","description":"Îndrumare expertă și consiliere strategică pentru a naviga provocările complexe de afaceri și a accelera creșterea.","cta_button":"Programează o Consultație"},"key_features":{"title":"Soluții Complete de Consultanță","features":[{"title":"Planificare Strategică","description":"Dezvoltarea strategiilor de afaceri comprehensive aliniate cu oportunitățile de piață și obiectivele companiei.","icon":"Target"},{"title":"Analiza Pieței","description":"Cercetare de piață aprofundată și inteligență competitivă pentru a informa deciziile strategice.","icon":"BarChart3"},{"title":"Strategie de Creștere","description":"Identificarea și executarea oportunităților de creștere inclusiv M&A, parteneriate și extinderea pieței.","icon":"TrendingUp"},{"title":"Piețe de Capital","description":"Îndrumare expertă privind strângerea de capital, targetarea investitorilor și strategiile de poziționare pe piață.","icon":"DollarSign"},{"title":"Guvernanță Corporativă","description":"Cele mai bune practici pentru eficiența consiliului, relațiile cu acționarii și conformitatea ESG.","icon":"Shield"},{"title":"Coaching Executiv","description":"Dezvoltarea leadership-ului și training de comunicare executivă pentru directori C-suite.","icon":"Users"}]},"benefits":{"title":"De Ce Să Alegi Consultanța AmplifiX","items":[{"title":"Expertiză în Industrie","description":"Cunoștințe profunde ale sectorului în tehnologie, sănătate, finanțe și industrii emergente."},{"title":"Track Record Dovedit","description":"Rezultate de succes pentru companii de la pre-IPO până la Fortune 500."},{"title":"Abordare Integrată","description":"Servicii de consultanță integrate perfect cu platformele noastre IR/PR și analiză."},{"title":"Confidențial și de Încredere","description":"Protocoale stricte de confidențialitate și relații de consilier de încredere bazate pe integritate."}]}}}'),
('th', 'advisory', '{"advisory":{"hero":{"title":"บริการ","title_highlight":"ที่ปรึกษาเชิงกลยุทธ์","description":"คำแนะนำจากผู้เชี่ยวชาญและคำปรึกษาเชิงกลยุทธ์เพื่อนำทางความท้าทายทางธุรกิจที่ซับซ้อนและเร่งการเติบโต","cta_button":"นัดหมายปรึกษา"},"key_features":{"title":"โซลูชันที่ปรึกษาครบวงจร","features":[{"title":"การวางแผนกลยุทธ์","description":"พัฒนากลยุทธ์ธุรกิจที่ครอบคลุมสอดคล้องกับโอกาสทางการตลาดและวัตถุประสงค์ของบริษัท","icon":"Target"},{"title":"การวิเคราะห์ตลาด","description":"การวิจัยตลาดเชิงลึกและข่าวกรองการแข่งขันเพื่อแจ้งการตัดสินใจเชิงกลยุทธ์","icon":"BarChart3"},{"title":"กลยุทธ์การเติบโต","description":"ระบุและดำเนินการโอกาสการเติบโตรวมถึง M&A พันธมิตร และการขยายตลาด","icon":"TrendingUp"},{"title":"ตลาดทุน","description":"คำแนะนำจากผู้เชี่ยวชาญเกี่ยวกับการระดมทุน การกำหนดเป้าหมายนักลงทุน และกลยุทธ์การวางตำแหน่งตลาด","icon":"DollarSign"},{"title":"ธรรมาภิบาลองค์กร","description":"แนวทางปฏิบัติที่ดีที่สุดสำหรับประสิทธิภาพคณะกรรมการ ความสัมพันธ์กับผู้ถือหุ้น และการปฏิบัติตาม ESG","icon":"Shield"},{"title":"การโค้ชผู้บริหาร","description":"การพัฒนาความเป็นผู้นำและการฝึกอบรมการสื่อสารสำหรับผู้บริหารระดับ C-suite","icon":"Users"}]},"benefits":{"title":"ทำไมต้องเลือกที่ปรึกษา AmplifiX","items":[{"title":"ความเชี่ยวชาญในอุตสาหกรรม","description":"ความรู้เชิงลึกในภาคเทคโนโลยี การดูแลสุขภาพ การเงิน และอุตสาหกรรมเกิดใหม่"},{"title":"ผลงานที่พิสูจน์แล้ว","description":"ผลลัพธ์ที่ประสบความสำเร็จสำหรับบริษัทตั้งแต่ pre-IPO จนถึง Fortune 500"},{"title":"แนวทางบูรณาการ","description":"บริการที่ปรึกษาผสานกับแพลตฟอร์ม IR/PR และการวิเคราะห์ของเราอย่างราบรื่น"},{"title":"เป็นความลับและน่าเชื่อถือ","description":"โปรโตคอลการรักษาความลับที่เข้มงวดและความสัมพันธ์ที่ปรึกษาที่เชื่อถือได้บนพื้นฐานความซื่อสัตย์"}]}}}'),
('tr', 'advisory', '{"advisory":{"hero":{"title":"Stratejik","title_highlight":"Danışmanlık Hizmetleri","description":"Karmaşık iş zorluklarını aşmak ve büyümeyi hızlandırmak için uzman rehberliği ve stratejik danışmanlık.","cta_button":"Danışma Planla"},"key_features":{"title":"Kapsamlı Danışmanlık Çözümleri","features":[{"title":"Stratejik Planlama","description":"Pazar fırsatları ve şirket hedefleriyle uyumlu kapsamlı iş stratejileri geliştirme.","icon":"Target"},{"title":"Pazar Analizi","description":"Stratejik kararları bilgilendirmek için derinlemesine pazar araştırması ve rekabet istihbaratı.","icon":"BarChart3"},{"title":"Büyüme Stratejisi","description":"M&A, ortaklıklar ve pazar genişlemesi dahil büyüme fırsatlarını belirleme ve uygulama.","icon":"TrendingUp"},{"title":"Sermaye Piyasaları","description":"Sermaye artırma, yatırımcı hedefleme ve pazar konumlandırma stratejileri konusunda uzman rehberlik.","icon":"DollarSign"},{"title":"Kurumsal Yönetim","description":"Yönetim kurulu etkinliği, hissedar ilişkileri ve ESG uyumu için en iyi uygulamalar.","icon":"Shield"},{"title":"Yönetici Koçluğu","description":"C-seviye yöneticiler için liderlik gelişimi ve yönetici iletişim eğitimi.","icon":"Users"}]},"benefits":{"title":"Neden AmplifiX Danışmanlığı Seçmelisiniz","items":[{"title":"Sektör Uzmanlığı","description":"Teknoloji, sağlık, finans ve gelişen sektörlerde derin sektör bilgisi."},{"title":"Kanıtlanmış Başarı","description":"Pre-IPO''dan Fortune 500''e kadar şirketler için başarılı sonuçlar."},{"title":"Entegre Yaklaşım","description":"IR/PR ve analitik platformlarımızla sorunsuz entegre danışmanlık hizmetleri."},{"title":"Gizli ve Güvenilir","description":"Dürüstlük üzerine kurulu sıkı gizlilik protokolleri ve güvenilir danışman ilişkileri."}]}}}'),
('uk', 'advisory', '{"advisory":{"hero":{"title":"Стратегічні","title_highlight":"Консультаційні Послуги","description":"Експертне керівництво та стратегічні консультації для подолання складних бізнес-викликів та прискорення зростання.","cta_button":"Запланувати Консультацію"},"key_features":{"title":"Комплексні Консультаційні Рішення","features":[{"title":"Стратегічне Планування","description":"Розробка комплексних бізнес-стратегій, узгоджених з ринковими можливостями та цілями компанії.","icon":"Target"},{"title":"Аналіз Ринку","description":"Поглиблене дослідження ринку та конкурентна розвідка для інформування стратегічних рішень.","icon":"BarChart3"},{"title":"Стратегія Зростання","description":"Визначення та реалізація можливостей зростання, включаючи M&A, партнерства та розширення ринку.","icon":"TrendingUp"},{"title":"Ринки Капіталу","description":"Експертне керівництво з залучення капіталу, таргетування інвесторів та стратегій позиціонування на ринку.","icon":"DollarSign"},{"title":"Корпоративне Управління","description":"Найкращі практики для ефективності ради директорів, відносин з акціонерами та відповідності ESG.","icon":"Shield"},{"title":"Коучинг Керівників","description":"Розвиток лідерства та навчання комунікації для керівників C-рівня.","icon":"Users"}]},"benefits":{"title":"Чому AmplifiX Консультації","items":[{"title":"Галузева Експертиза","description":"Глибокі знання секторів технологій, охорони здоров''я, фінансів та галузей, що розвиваються."},{"title":"Перевірений Досвід","description":"Успішні результати для компаній від pre-IPO до Fortune 500."},{"title":"Інтегрований Підхід","description":"Консультаційні послуги, безшовно інтегровані з нашими IR/PR та аналітичними платформами."},{"title":"Конфіденційно та Надійно","description":"Суворі протоколи конфіденційності та довірчі консультаційні відносини, побудовані на чесності."}]}}}')
INSERT INTO translations (language_code, namespace, content)
VALUES 
('ar', 'analytics', '{"analytics":{"hero":{"title":"البحث و","title_highlight":"التحليلات","description":"تحويل البيانات إلى رؤى قابلة للتنفيذ مع تحليلات متقدمة ولوحات معلومات استخباراتية في الوقت الفعلي.","cta_button":"استكشف التحليلات"},"key_features":{"title":"مجموعة تحليلات شاملة","features":[{"title":"مشاعر السوق","description":"تحليل المشاعر في الوقت الفعلي عبر الأخبار ووسائل التواصل الاجتماعي واتصالات المستثمرين.","icon":"TrendingUp"},{"title":"ذكاء المستثمرين","description":"تتبع سلوك المستثمرين وتغييرات الملكية وأنماط النشاط المؤسسي.","icon":"Users"},{"title":"التحليل التنافسي","description":"مراقبة اتصالات المنافسين وموقعهم في السوق ومقاييس حصة الصوت.","icon":"BarChart3"},{"title":"مراقبة الوسائط","description":"تتبع التغطية الشاملة عبر الوسائط التقليدية والرقمية والبث.","icon":"FileText"},{"title":"مقاييس الأداء","description":"قياس فعالية حملات IR/PR مع تحليل الإسناد والعائد على الاستثمار المفصل.","icon":"Target"},{"title":"رؤى تنبؤية","description":"التنبؤ بالذكاء الاصطناعي واكتشاف الاتجاهات لتوقع تحركات السوق.","icon":"Lightbulb"}]},"benefits":{"title":"لماذا تحليلات AmplifiX","items":[{"title":"استخبارات في الوقت الفعلي","description":"لوحات معلومات حية مع تنبيهات فورية على الأحداث المادية وتحولات السوق."},{"title":"رؤى بالذكاء الاصطناعي","description":"نماذج التعلم الآلي المدربة على الاتصالات المالية وبيانات السوق."},{"title":"تقارير مخصصة","description":"تقارير وتصورات مخصصة لعروض مجلس الإدارة واجتماعات المستثمرين."},{"title":"تكامل البيانات","description":"تكامل سلس مع أدواتك الحالية وCRM والبنية التحتية للبيانات."}]}}}'),
('ro', 'analytics', '{"analytics":{"hero":{"title":"Cercetare și","title_highlight":"Analiză","description":"Transformă datele în informații acționabile cu analize avansate și tablouri de bord de inteligență în timp real.","cta_button":"Explorează Analitica"},"key_features":{"title":"Suită Completă de Analiză","features":[{"title":"Sentimentul Pieței","description":"Analiză a sentimentului în timp real pe știri, social media și comunicații cu investitorii.","icon":"TrendingUp"},{"title":"Inteligență Investitori","description":"Urmărește comportamentul investitorilor, schimbările de proprietate și tiparele de activitate instituțională.","icon":"Users"},{"title":"Analiză Competitivă","description":"Monitorizează comunicațiile competitorilor, poziționarea pe piață și metricile de share of voice.","icon":"BarChart3"},{"title":"Monitorizare Media","description":"Urmărire completă a acoperirii media tradiționale, digitale și broadcast.","icon":"FileText"},{"title":"Metrici de Performanță","description":"Măsoară eficiența campaniilor IR/PR cu analiză detaliată de atribuire și ROI.","icon":"Target"},{"title":"Insights Predictive","description":"Prognoză bazată pe AI și detectarea tendințelor pentru a anticipa mișcările pieței.","icon":"Lightbulb"}]},"benefits":{"title":"De Ce Analitica AmplifiX","items":[{"title":"Inteligență în Timp Real","description":"Tablouri de bord live cu alerte instantanee pentru evenimente materiale și schimbări de piață."},{"title":"Insights Bazate pe AI","description":"Modele de machine learning antrenate pe comunicații financiare și date de piață."},{"title":"Raportare Personalizată","description":"Rapoarte și vizualizări personalizate pentru prezentări în consiliu și întâlniri cu investitorii."},{"title":"Integrare Date","description":"Integrare perfectă cu instrumentele existente, CRM și infrastructura de date."}]}}}'),
('th', 'analytics', '{"analytics":{"hero":{"title":"การวิจัยและ","title_highlight":"การวิเคราะห์","description":"เปลี่ยนข้อมูลเป็นข้อมูลเชิงลึกที่นำไปปฏิบัติได้ด้วยการวิเคราะห์ขั้นสูงและแดชบอร์ดข่าวกรองแบบเรียลไทม์","cta_button":"สำรวจการวิเคราะห์"},"key_features":{"title":"ชุดการวิเคราะห์ครบวงจร","features":[{"title":"ความรู้สึกตลาด","description":"การวิเคราะห์ความรู้สึกแบบเรียลไทม์ข้ามข่าว โซเชียลมีเดีย และการสื่อสารกับนักลงทุน","icon":"TrendingUp"},{"title":"ข่าวกรองนักลงทุน","description":"ติดตามพฤติกรรมนักลงทุน การเปลี่ยนแปลงความเป็นเจ้าของ และรูปแบบกิจกรรมสถาบัน","icon":"Users"},{"title":"การวิเคราะห์การแข่งขัน","description":"ติดตามการสื่อสารของคู่แข่ง ตำแหน่งตลาด และตัวชี้วัด share of voice","icon":"BarChart3"},{"title":"การติดตามสื่อ","description":"การติดตามครอบคลุมข้ามสื่อดั้งเดิม ดิจิทัล และช่องทางการออกอากาศ","icon":"FileText"},{"title":"ตัวชี้วัดประสิทธิภาพ","description":"วัดประสิทธิผลแคมเปญ IR/PR ด้วยการวิเคราะห์การระบุแหล่งที่มาและ ROI อย่างละเอียด","icon":"Target"},{"title":"ข้อมูลเชิงลึกเชิงพยากรณ์","description":"การพยากรณ์ด้วย AI และการตรวจจับแนวโน้มเพื่อคาดการณ์การเคลื่อนไหวของตลาด","icon":"Lightbulb"}]},"benefits":{"title":"ทำไมต้องการวิเคราะห์ AmplifiX","items":[{"title":"ข่าวกรองแบบเรียลไทม์","description":"แดชบอร์ดสดพร้อมการแจ้งเตือนทันทีเกี่ยวกับเหตุการณ์สำคัญและการเปลี่ยนแปลงของตลาด"},{"title":"ข้อมูลเชิงลึกจาก AI","description":"โมเดล machine learning ที่ฝึกบนการสื่อสารทางการเงินและข้อมูลตลาด"},{"title":"รายงานที่กำหนดเอง","description":"รายงานและการแสดงผลที่ปรับแต่งสำหรับการนำเสนอคณะกรรมการและการประชุมนักลงทุน"},{"title":"การรวมข้อมูล","description":"การรวมอย่างราบรื่นกับเครื่องมือที่มีอยู่ CRM และโครงสร้างพื้นฐานข้อมูล"}]}}}'),
('tr', 'analytics', '{"analytics":{"hero":{"title":"Araştırma ve","title_highlight":"Analitik","description":"Gelişmiş analitik ve gerçek zamanlı istihbarat panelleriyle verileri eyleme dönüştürülebilir içgörülere dönüştürün.","cta_button":"Analitiği Keşfet"},"key_features":{"title":"Kapsamlı Analitik Paketi","features":[{"title":"Piyasa Duygusu","description":"Haberler, sosyal medya ve yatırımcı iletişimleri genelinde gerçek zamanlı duygu analizi.","icon":"TrendingUp"},{"title":"Yatırımcı İstihbaratı","description":"Yatırımcı davranışını, mülkiyet değişikliklerini ve kurumsal aktivite kalıplarını takip edin.","icon":"Users"},{"title":"Rekabet Analizi","description":"Rakip iletişimlerini, pazar konumlandırmasını ve ses payı metriklerini izleyin.","icon":"BarChart3"},{"title":"Medya İzleme","description":"Geleneksel medya, dijital ve yayın kanalları genelinde kapsamlı kapsam takibi.","icon":"FileText"},{"title":"Performans Metrikleri","description":"Ayrıntılı atıf ve ROI analiziyle IR/PR kampanya etkinliğini ölçün.","icon":"Target"},{"title":"Tahmine Dayalı İçgörüler","description":"Piyasa hareketlerini önceden tahmin etmek için AI destekli öngörü ve trend tespiti.","icon":"Lightbulb"}]},"benefits":{"title":"Neden AmplifiX Analitik","items":[{"title":"Gerçek Zamanlı İstihbarat","description":"Önemli olaylar ve piyasa değişimleri için anlık uyarılarla canlı paneller."},{"title":"AI Destekli İçgörüler","description":"Finansal iletişimler ve piyasa verileri üzerinde eğitilmiş makine öğrenimi modelleri."},{"title":"Özel Raporlama","description":"Yönetim kurulu sunumları ve yatırımcı toplantıları için özelleştirilmiş raporlar ve görselleştirmeler."},{"title":"Veri Entegrasyonu","description":"Mevcut araçlarınız, CRM''niz ve veri altyapınızla sorunsuz entegrasyon."}]}}}'),
('uk', 'analytics', '{"analytics":{"hero":{"title":"Дослідження та","title_highlight":"Аналітика","description":"Перетворюйте дані на практичні інсайти за допомогою розширеної аналітики та інформаційних панелей у реальному часі.","cta_button":"Дослідити Аналітику"},"key_features":{"title":"Комплексний Аналітичний Пакет","features":[{"title":"Настрої Ринку","description":"Аналіз настроїв у реальному часі через новини, соціальні мережі та комунікації з інвесторами.","icon":"TrendingUp"},{"title":"Розвідка Інвесторів","description":"Відстежуйте поведінку інвесторів, зміни власності та моделі інституційної активності.","icon":"Users"},{"title":"Конкурентний Аналіз","description":"Моніторинг комунікацій конкурентів, позиціонування на ринку та метрик частки голосу.","icon":"BarChart3"},{"title":"Медіа-моніторинг","description":"Комплексне відстеження охоплення через традиційні медіа, цифрові та ефірні канали.","icon":"FileText"},{"title":"Метрики Ефективності","description":"Вимірюйте ефективність IR/PR кампаній з детальним аналізом атрибуції та ROI.","icon":"Target"},{"title":"Прогнозні Інсайти","description":"Прогнозування на основі AI та виявлення трендів для передбачення рухів ринку.","icon":"Lightbulb"}]},"benefits":{"title":"Чому Аналітика AmplifiX","items":[{"title":"Розвідка в Реальному Часі","description":"Живі панелі з миттєвими сповіщеннями про матеріальні події та зміни ринку."},{"title":"Інсайти на Основі AI","description":"Моделі машинного навчання, навчені на фінансових комунікаціях та ринкових даних."},{"title":"Індивідуальна Звітність","description":"Налаштовані звіти та візуалізації для презентацій раді директорів та зустрічей з інвесторами."},{"title":"Інтеграція Даних","description":"Безшовна інтеграція з вашими існуючими інструментами, CRM та інфраструктурою даних."}]}}}')
